#!/usr/bin/env python3"""ClawTeam 鍋ュ悍妫€鏌?Dashboard v1.0.0绾?Python 鍐呯疆搴撳疄鐜帮紝鏀寔 serve 鍜?export 涓ょ妯″紡"""__version__ = "1.0.0"import http.serverimport jsonimport pathlibimport datetimeimport socketimport sysimport osimport iofrom typing import Optional# 淇 Windows 缁堢缂栫爜if sys.platform == "win32":    sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding="utf-8", errors="replace")    sys.stderr = io.TextIOWrapper(sys.stderr.buffer, encoding="utf-8", errors="replace")# 璺緞閰嶇疆TEAMS_DIR = pathlib.Path(os.environ.get("CLAWTEAM_SHARED", pathlib.Path(__file__).parent.parent.parent / "shared" / "team-brain" / "teams"))SCRIPT_DIR = pathlib.Path(__file__).parentdef load_teams() -> list[dict]:    """璇诲彇鎵€鏈夊洟闃熺姸鎬佹枃浠?""    teams = []    if not TEAMS_DIR.exists():        return teams    for f in TEAMS_DIR.glob("*.json"):        try:            data = json.loads(f.read_text(encoding="utf-8"))            data["_file"] = f.name            teams.append(data)        except Exception:            pass    return sorted(teams, key=lambda x: x.get("created_at", ""))def get_health_status(agent_statuses: list) -> tuple[str, str]:    """鏍规嵁 agent 鐘舵€佽绠楀仴搴风姸鎬?""    if not agent_statuses:        return "馃敶", "鏃?Agent"    alive = sum(1 for s in agent_statuses if s.get("status") != "dead")    total = len(agent_statuses)    ratio = alive / total    if ratio >= 0.8:        return "馃煝", f"{alive}/{total} 娲昏穬"    elif ratio >= 0.5:        return "馃煛", f"{alive}/{total} 娲昏穬"    else:        return "馃敶", f"{alive}/{total} 娲昏穬"def escape_html(text: str) -> str:    """HTML 杞箟"""    return (str(text)            .replace("&", "&amp;")            .replace("<", "&lt;")            .replace(">", "&gt;")            .replace('"', "&quot;")            .replace("'", "&#39;"))def build_html(teams: list[dict], title: str = "ClawTeam 鍋ュ悍妫€鏌?Dashboard") -> str:    """鐢熸垚 HTML 椤甸潰"""    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")        # 缁熻姹囨€?    total_teams = len(teams)    total_agents = 0    alive_agents = 0    fail_count = 0        team_rows = []    for team in teams:        agents = team.get("agents", [])        total_agents += len(agents)        alive_agents += sum(1 for a in agents if a.get("status") != "dead")                health_icon, health_text = get_health_status(agents)        phase = escape_html(team.get("phase", team.get("current_phase", team.get("stage", "鈥?))))        task_name = escape_html(team.get("task_name", team.get("name", "鈥?)))        team_id = escape_html(team.get("team_id", "鈥?))                # 鏀堕泦閿欒淇℃伅        errors = []        for a in agents:            err = a.get("error_message") or a.get("last_error")            if err:                errors.append(f"{escape_html(a.get('agent_id', a.get('name', '?')))}: {escape_html(err)}")                error_cell = ""        if errors:            error_cell = f"<details class='errors'><summary>鈿?{len(errors)} 涓敊璇?/summary><ul>" + "".join(f"<li>{e}</li>" for e in errors) + "</ul></details>"                # 璁＄畻瀛樻椿鏃堕棿        created = team.get("created_at", "")        age_text = ""        if created:            try:                dt = datetime.datetime.fromisoformat(created.replace("Z", "+00:00"))                age = datetime.datetime.now() - dt.replace(tzinfo=None)                mins = int(age.total_seconds() / 60)                age_text = f"{mins} 鍒嗛挓"            except Exception:                age_text = "鈥?        row_class = "fail" if health_icon == "馃敶" else ("warn" if health_icon == "馃煛" else "ok")        team_rows.append(f"""<tr class="{row_class}">            <td><code>{team_id}</code></td>            <td>{task_name}</td>            <td>{phase}</td>            <td>{age_text}</td>            <td class="health">{health_icon} {health_text}</td>            <td>{error_cell}</td>        </tr>""")                if health_icon == "馃敶":            fail_count += 1    if not team_rows:        team_rows.append("<tr><td colspan='6' style='text-align:center;color:#888'>鏆傛棤鍥㈤槦鏁版嵁</td></tr>")    html = f"""<!DOCTYPE html><html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>{escape_html(title)}</title><style>* {{ box-sizing: border-box; margin: 0; padding: 0; }}body {{ font-family: -apple-system, "Segoe UI", Arial, sans-serif; background: #0f1419; color: #e7e9ea; min-height: 100vh; padding: 24px; }}.header {{ display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px; flex-wrap: wrap; gap: 12px; }}h1 {{ font-size: 22px; font-weight: 600; color: #f7f9f9; }}.timestamp {{ color: #71767b; font-size: 13px; }}.summary {{ display: flex; gap: 16px; margin-bottom: 20px; flex-wrap: wrap; }}.stat {{ background: #1c2732; border-radius: 8px; padding: 12px 20px; }}.stat-label {{ font-size: 12px; color: #71767b; text-transform: uppercase; margin-bottom: 4px; }}.stat-value {{ font-size: 22px; font-weight: 600; }}.stat-ok {{ color: #00ba7c; }}.stat-warn {{ color: #ffd60a; }}.stat-fail {{ color: #f4212e; }}.stat-total {{ color: #f7f9f9; }}table {{ width: 100%; border-collapse: collapse; background: #1c2732; border-radius: 12px; overflow: hidden; }}th {{ background: #27333d; color: #71767b; font-size: 12px; text-transform: uppercase; padding: 12px 16px; text-align: left; font-weight: 500; }}td {{ padding: 12px 16px; border-top: 1px solid #2f3336; vertical-align: top; font-size: 14px; }}tr.ok td {{ color: #e7e9ea; }}tr.warn td {{ background: rgba(255,214,10,0.05); }}tr.fail td {{ background: rgba(244,33,46,0.08); }}td.health {{ font-weight: 600; white-space: nowrap; }}code {{ background: #2f3336; padding: 2px 6px; border-radius: 4px; font-size: 12px; }}.errors {{ margin-top: 4px; font-size: 12px; color: #f4212e; }}.errors ul {{ margin-top: 4px; padding-left: 16px; color: #f4212e; }}.errors summary {{ cursor: pointer; color: #f4212e; }}.footer {{ margin-top: 24px; text-align: center; color: #71767b; font-size: 12px; }}.refresh {{ color: #1d9bf0; text-decoration: none; }}@media (max-width: 700px) {{ table {{display: block; overflow-x: auto; }} }}</style></head><body><div class="header">    <h1>馃惥 ClawTeam 鍋ュ悍妫€鏌?/h1>    <span class="timestamp">馃晲 {now}</span></div><div class="summary">    <div class="stat">        <div class="stat-label">鍥㈤槦鎬绘暟</div>        <div class="stat-value stat-total">{total_teams}</div>    </div>    <div class="stat">        <div class="stat-label">Agent 瀛樻椿</div>        <div class="stat-value stat-ok">{alive_agents}/{total_agents}</div>    </div>    <div class="stat">        <div class="stat-label">寮傚父鍥㈤槦</div>        <div class="stat-value stat-fail">{fail_count}</div>    </div></div><table><thead><tr>    <th>Team ID</th>    <th>浠诲姟鍚?/th>    <th>闃舵</th>    <th>杩愯鏃堕暱</th>    <th>鍋ュ悍鐘舵€?/th>    <th>閿欒璇︽儏</th></tr></thead><tbody>{chr(10).join(team_rows)}</tbody></table><div class="footer">    鑷姩鍒锋柊 路 <a href="javascript:location.reload()" class="refresh">绔嬪嵆鍒锋柊</a></div><script>(function(){{    let remaining = 10;    const tick = () => {{        const el = document.getElementById('countdown');        if(el) el.textContent = remaining;        if(remaining-- <= 0) {{ location.reload(); return; }}        setTimeout(tick, 1000);    }};    document.write('<span id="countdown" style="color:#71767b"></span>');    document.close();    setTimeout(tick, 0);}})();</script></body></html>"""    return htmldef export_html(output_path: Optional[str] = None, team_id: Optional[str] = None):    """瀵煎嚭 HTML 鏂囦欢"""    teams = load_teams()    if team_id:        teams = [t for t in teams if t.get("team_id") == team_id]    html = build_html(teams)        if output_path:        # 鐢ㄦ埛鎸囧畾璺緞锛氭敮鎸?~ 灞曞紑鍜?Windows 璺緞        path = pathlib.Path(output_path).expanduser().resolve()    else:        # Default path: use ~/.qclaw/shared/team-brain/dashboard/        default_root = pathlib.Path.home() / ".qclaw" / "shared" / "team-brain" / "dashboard"        if sys.platform == "win32":            path = default_root / "health-report.html"        else:            path = SCRIPT_DIR / "health-report.html"        # 鍒涘缓鐖剁洰褰?    path.parent.mkdir(parents=True, exist_ok=True)        path.write_text(html, encoding="utf-8")    print(f"鉁?宸插鍑? {path.resolve()}")    return pathdef get_local_ip() -> str:    """鑾峰彇鏈満 IP"""    try:        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)        s.connect(("8.8.8.8", 80))        ip = s.getsockname()[0]        s.close()        return ip    except Exception:        return "127.0.0.1"class DashboardHandler(http.server.SimpleHTTPRequestHandler):    """Web 鏈嶅姟澶勭悊鍣?""        def do_GET(self):        if self.path == "/" or self.path == "/index.html":            teams = load_teams()            html = build_html(teams)            self.send_response(200)            self.send_header("Content-Type", "text/html; charset=utf-8")            self.send_header("Refresh", "10")            self.end_headers()            self.wfile.write(html.encode("utf-8"))        else:            super().do_GET()        def log_message(self, format, *args):        print(f"[{datetime.datetime.now().strftime('%H:%M:%S')}] {args[0]}")def serve(port: int = 8080):    """鍚姩 Web 鏈嶅姟鍣?""    handler = DashboardHandler    # 閲嶅畾鍚戝綋鍓嶇洰褰曞埌鑴氭湰鎵€鍦ㄧ洰褰?    os.chdir(SCRIPT_DIR)    server = http.server.HTTPServer(("0.0.0.0", port), handler)    local_ip = get_local_ip()    print(f"""鈺斺晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晽鈺?  馃惥 ClawTeam 鍋ュ悍妫€鏌?Dashboard        鈺?鈺犫晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨暎鈺?  Local:  http://localhost:{port}           鈺?鈺?  LAN:    http://{local_ip}:{port}       鈺?鈺?  鏁版嵁婧? {TEAMS_DIR}     鈺?鈺犫晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨暎鈺?  姣?10 绉掕嚜鍔ㄥ埛鏂? 路  Ctrl+C 鍋滄      鈺?鈺氣晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨暆""")    try:        server.serve_forever()    except KeyboardInterrupt:        print("\n馃憢 鍋滄鏈嶅姟")        server.shutdown()if __name__ == "__main__":    cmd = sys.argv[1] if len(sys.argv) > 1 else "serve"    arg = sys.argv[2] if len(sys.argv) > 2 else None    if cmd == "serve":        port = int(arg) if arg else 8080        serve(port)    elif cmd == "export":        team_id = sys.argv[3] if len(sys.argv) > 3 else None        export_html(arg, team_id)    else:        print(f"鐢ㄦ硶: python {sys.argv[0]} serve [port] | export [output_path] [team_id]")        sys.exit(1)